output.message:
{
  "steps": [
    {
      "step_id": "cb_step_1",
      "title": "Select Pelvic CT Volume",
      "simple": "Choose the Pelvic Volume from the dropdown.",
      "detailed": "This step selects the CT scan of the pelvis that will be used for segmentation and fracture planning. The correct volume is essential because all subsequent steps depend on this image data. In the 'Input CT Volume' dropdown, select the pelvic volume you imported earlier."
    },
    {
      "step_id": "cb_step_2",
      "title": "Segment the Pelvis",
      "simple": "Click the 'Run Step 1: Segment Pelvis' button.",
      "detailed": "This step automatically identifies and segments the pelvic bone from the CT volume using the extension's built-in algorithm. A segmentation of the entire pelvis is created as the foundation for fracture analysis and surgical planning. Simply click the button and wait for the process to complete."
    },
    {
      "step_id": "cb_step_3",
      "title": "Segment Fractures",
      "simple": "Click the 'Run Step 2: Segment Fractures' button.",
      "detailed": "This step automatically detects and segments individual fracture fragments from the pelvic segmentation. Each fragment becomes a separate segment, allowing you to visualize and manipulate displaced bone pieces. Click the button to run the fracture segmentation."
    },
    {
      "step_id": "cb_step_4",
      "title": "Exclude Unwanted Fragments",
      "simple": "Untick any fracture fragments you want to exclude from the surgical plan.",
      "detailed": "You may exclude small or irrelevant bone fragments that do not require reduction or screw fixation. Unticking a fragment removes it from the template generation and reduction steps, focusing the plan on the clinically significant pieces. Review the listed segments and uncheck any that should be omitted."
    },
    {
      "step_id": "cb_step_5",
      "title": "Generate Reduction Template",
      "simple": "Click the 'Run Step 3: Generate Template' button.",
      "detailed": "This step creates a template model of the intact pelvic shape by aligning and reconstructing the fracture fragments. The template serves as the anatomical target for reducing the fracture. Click the button to generate the template."
    },
    {
      "step_id": "cb_step_6",
      "title": "Register and Reduce Fracture",
      "simple": "Click the 'Run Step 4: Register & Reduce' button.",
      "detailed": "This step aligns each fracture fragment to the template using registration algorithms, simulating the reduction of the pelvis to its anatomical alignment. The result is a reduced pelvic segmentation that approximates the pre-injury configuration. Click the button to perform the automated reduction."
    },
    {
      "step_id": "cb_step_7",
      "title": "Decide on Manual Adjustment",
      "simple": "Tick the checkbox if you need to manually adjust any fragment; otherwise leave unticked and proceed.",
      "detailed": "After automated reduction, you may need to fine-tune the position of certain fragments for a more accurate alignment. Tick the 'Manually adjust a fragment' checkbox to enable the adjustment tools. If the reduction looks satisfactory, leave the checkbox unticked and skip to step 11."
    },
    {
      "step_id": "cb_step_8",
      "title": "Select Fragment to Adjust",
      "simple": "Choose the fragment you want to adjust from the dropdown list.",
      "detailed": "Select the specific bone fragment that requires manual repositioning. This ensures your adjustments are applied to the correct piece. From the 'Fragment' selection box, pick the fragment you wish to move or rotate."
    },
    {
      "step_id": "cb_step_9",
      "title": "Adjust Fragment Position and Rotation",
      "simple": "Use the transform controls to manually move and rotate the selected fragment.",
      "detailed": "Fine-tune the alignment of the fragment by dragging it with the transform manipulator. Rotate and translate it until it fits correctly against adjacent bone surfaces. This manual adjustment allows you to correct any residual displacement not resolved by the automated reduction."
    },
    {
      "step_id": "cb_step_10",
      "title": "Apply Fragment Adjustments",
      "simple": "Click the 'Apply adjustments' button to save the manual changes.",
      "detailed": "Once you are satisfied with the fragment's position, click 'Apply adjustments' to commit the transformation and update the reduced pelvic model. This finalizes the manual correction before moving to screw planning."
    },
    {
      "step_id": "cb_step_11",
      "title": "Plan Screw Trajectories",
      "simple": "Click the 'Run Step 5: Plan Screws' button.",
      "detailed": "This step automatically computes optimal screw trajectories for fixing the reduced fracture fragments. The system generates screw models based on bone geometry and typical fixation paths. Click the button to generate the screw plan."
    },
    {
      "step_id": "cb_step_12",
      "title": "Decide on Screw Editing",
      "simple": "Tick the checkbox if you want to manually edit screw trajectories; otherwise leave unticked to finish.",
      "detailed": "The automated screw plan may need refinement to avoid critical structures or improve fixation. Tick the 'Edit Screw trajectories' checkbox to manually adjust screw positions and orientations. If the plan is acceptable, leave unticked and the workflow is complete."
    },
    {
      "step_id": "cb_step_13",
      "title": "Adjust Screw Trajectories",
      "simple": "Use the transform controls to adjust the position and orientation of the screw trajectories.",
      "detailed": "Manually fine-tune each screw trajectory by moving and rotating the screw model. Ensure screws are safely placed within bone corridors and avoid neurovascular structures. Adjust as needed to optimize the fixation plan."
    },
    {
      "step_id": "cb_step_14",
      "title": "Regenerate Screws from Edits",
      "simple": "Click the 'Regenerate screws from edited lines' button to update the screw models.",
      "detailed": "After manually adjusting screw trajectories, click this button to regenerate the screw models that reflect your changes. This ensures the final screw geometry matches your edited paths."
    },
    {
      "step_id": "cb_step_15",
      "title": "Finalize Screw Plan",
      "simple": "Untick the 'Edit Screw trajectories' checkbox to complete the planning.",
      "detailed": "Once you are satisfied with all screw adjustments, untick the checkbox to close the editing mode. The finalized screw trajectories are now part of the surgical plan."
    }
  ]
}
